170	    long long calculate_sum_sq_comp_size() const {
171	        long long total_sq_sum = 0;
172	        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
173	        for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);
174	
175	        std::array<std::pair<int, int>, GRID_SIZE * GRID_SIZE> q_arr; 
176	
177	        for (int r_start = 0; r_start < GRID_SIZE; ++r_start) {
178	            for (int c_start = 0; c_start < GRID_SIZE; ++c_start) {
179	                if (board[r_start][c_start] != 0 && !visited[r_start][c_start]) {
180	                    int current_flavor = board[r_start][c_start];
181	                    long long current_comp_size = 0;
182	                    
183	                    q_arr[0] = {r_start, c_start};
184	                    visited[r_start][c_start] = true;
185	                    int head = 0; 
186	                    int tail = 1; 
187	                    
188	                    while(head < tail){
189	                        current_comp_size++; 
190	                        const std::pair<int,int>& curr_cell = q_arr[head];
191	                        const int curr_r = curr_cell.first;
192	                        const int curr_c = curr_cell.second;
193	                        head++; 
194	
195	                        for (int i = 0; i < NUM_DIRECTIONS; ++i) {
196	                            int nr = curr_r + DR[i];
197	                            int nc = curr_c + DC[i];
198	                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
199	                                !visited[nr][nc] && board[nr][nc] == current_flavor) {
200	                                visited[nr][nc] = true;
201	                                q_arr[tail++] = {nr, nc}; 
202	                            }
203	                        }
204	                    }
205	                    total_sq_sum += current_comp_size * current_comp_size;
206	                }
207	            }
208	        }
209	        return total_sq_sum;
210	    }
