212	    double calculate_distance_penalty_CoM() const {
213	        if (candies_list.empty()) return 0.0;
214	
215	        std::array<double, NUM_FLAVORS + 1> sum_r; sum_r.fill(0.0);
216	        std::array<double, NUM_FLAVORS + 1> sum_c; sum_c.fill(0.0);
217	        std::array<int, NUM_FLAVORS + 1> counts; counts.fill(0);
218	
219	        for (const auto& candy : candies_list) {
220	            counts[candy.flavor]++;
221	            sum_r[candy.flavor] += candy.r;
222	            sum_c[candy.flavor] += candy.c;
223	        }
224	
225	        std::array<std::pair<double, double>, NUM_FLAVORS + 1> com_coords;
226	        for (int fl = 1; fl <= NUM_FLAVORS; ++fl) {
227	            if (counts[fl] > 0) {
228	                com_coords[fl] = {sum_r[fl] / counts[fl], sum_c[fl] / counts[fl]};
229	            }
230	        }
231	
232	        double total_manhattan_dist_penalty = 0;
233	        for (const auto& candy : candies_list) {
234	            if (counts[candy.flavor] > 1) { 
235	                const auto& com = com_coords[candy.flavor];
236	                total_manhattan_dist_penalty += std::abs(static_cast<double>(candy.r) - com.first) + 
237	                                                std::abs(static_cast<double>(candy.c) - com.second);
238	            }
239	        }
240	        return total_manhattan_dist_penalty;
241	    }
