                    int f = board[r][c];
                    if (counts[f] > 1) {
                        double com_r = sum_r[f] / counts[f];
                        double com_c = sum_c[f] / counts[f];
                        compactness += std::abs(r - com_r) + std::abs(c - com_c);
                    }
                }
